      return { key, label: item.label || meta.label || key, intensity: Math.round(intensity), description: item.description || meta.description || '', cadence: meta.cadence || {}, accentCadence: item.accentCadence || {}, biomeAccent: item.biomeAccent || null, profile: Object.fromEntries(Core.TRAITS.map(t => [t.key, Core.normalizeTrait(emotionProfile[t.key])])) };
